<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use Illuminate\Http\Request; use Illuminate\Support\Facades\Hash; use App\Models\User;
class UserController extends Controller { public function index(){return view('admin.users.index',['users'=>User::latest()->paginate(20)]);} public function create(){return view('admin.users.form',['user'=>new User]);} public function store(Request $r){$d=$r->validate(['name'=>'required','email'=>'required|email|unique:users','password'=>'required|min:6','role'=>'required|in:super_admin,admin,staff','is_active'=>'nullable|boolean']); $d['password']=Hash::make($d['password']); $d['is_active']=$r->boolean('is_active'); User::create($d); return redirect()->route('admin.users.index')->with('success','เพิ่มผู้ใช้แล้ว');} public function edit(User $user){return view('admin.users.form',compact('user'));} public function update(Request $r,User $user){$d=$r->validate(['name'=>'required','email'=>'required|email|unique:users,email,'.$user->id,'password'=>'nullable|min:6','role'=>'required|in:super_admin,admin,staff','is_active'=>'nullable|boolean']); if($d['password']){$d['password']=Hash::make($d['password']);}else{unset($d['password']);} $d['is_active']=$r->boolean('is_active'); $user->update($d); return back()->with('success','บันทึกผู้ใช้แล้ว');} public function destroy(User $user){abort_if(auth()->id()===$user->id,422,'ห้ามลบบัญชีตัวเอง'); $user->delete(); return back()->with('success','ลบผู้ใช้แล้ว');} }
